import java.io.*;import java.net.*;import java.net.http.*;import java.nio.charset.StandardCharsets;import java.nio.file.*;import java.sql.*;import java.time.*;import java.util.regex.*;
public class MerchantBrowserToken{
 static final String API="http://127.0.0.1:18081"; static final String TEMP_PASSWORD="CodexTemp12!";
 record DbConfig(String url,String username,String password){}
 public static void main(String[]args)throws Exception{String username=latestUser();String token=login(username);Files.writeString(Path.of(".ai/tmp/merchant-browser-token.dat"),token);System.out.println("BROWSER_TOKEN_OK");}
 static String latestUser()throws Exception{DbConfig cfg=readDbConfig();try(Connection c=DriverManager.getConnection(cfg.url(),cfg.username(),cfg.password());Statement s=c.createStatement();ResultSet rs=s.executeQuery("select u.user_name from sys_user u join sys_tenant t on t.tenant_id=u.tenant_id join merchant_profile mp on mp.tenant_id=u.tenant_id where t.tenant_type='MERCHANT' and u.del_flag='0' and u.status='1' order by u.create_time desc nulls last limit 1")){if(!rs.next())throw new IllegalStateException("No merchant user");return rs.getString(1);}}
 static String login(String username)throws Exception{String captcha=http("GET",API+"/captchaImage",null,null).body();String uuid=extract(captcha,"\\\"uuid\\\"\\s*:\\s*\\\"([^\\\"]+)\\\"");String code=redisGet("captcha_codes:"+uuid).replace("\"","");String body="{\"username\":\""+username+"\",\"password\":\""+TEMP_PASSWORD+"\",\"code\":\""+code+"\",\"uuid\":\""+uuid+"\"}";String resp=http("POST",API+"/login",body,null).body();return extract(resp,"\\\"token\\\"\\s*:\\s*\\\"([^\\\"]+)\\\"");}
 static HttpResponse<String> http(String method,String url,String body,String token)throws Exception{HttpClient client=HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build();HttpRequest.Builder b=HttpRequest.newBuilder(URI.create(url)).timeout(Duration.ofSeconds(20)).header("Content-Language","zh_CN");if(token!=null)b.header("Authorization","Bearer "+token);if(body!=null)b.header("Content-Type","application/json").method(method,HttpRequest.BodyPublishers.ofString(body,StandardCharsets.UTF_8));else b.method(method,HttpRequest.BodyPublishers.noBody());return client.send(b.build(),HttpResponse.BodyHandlers.ofString(StandardCharsets.UTF_8));}
 static String redisGet(String key)throws Exception{try(Socket s=new Socket("127.0.0.1",6379)){s.setSoTimeout(3000);OutputStream out=s.getOutputStream();out.write(("*2\r\n$3\r\nGET\r\n$"+key.getBytes(StandardCharsets.UTF_8).length+"\r\n"+key+"\r\n").getBytes(StandardCharsets.UTF_8));out.flush();BufferedReader br=new BufferedReader(new InputStreamReader(s.getInputStream(),StandardCharsets.UTF_8));String header=br.readLine();if(header==null||header.startsWith("$-1"))throw new IllegalStateException("Redis key missing");String value=br.readLine();return value==null?"":value;}}
 static String extract(String text,String regex){Matcher m=Pattern.compile(regex).matcher(text);if(!m.find())throw new IllegalStateException("Pattern not found");return m.group(1);} 
 static DbConfig readDbConfig()throws Exception{String yml=Files.readString(Path.of("bocoo-admin/src/main/resources/application-dev.yml"));Matcher m=Pattern.compile("url:\\s*(jdbc:postgresql:[^\\r\\n]+).*?username:\\s*([^\\r\\n]+).*?password:\\s*([^\\r\\n]+)",Pattern.DOTALL).matcher(yml);if(!m.find())throw new IllegalStateException("DB config not found");return new DbConfig(m.group(1).trim(),m.group(2).trim(),m.group(3).trim());}
}